namespace sv_c41c24300fbf48f9881eb8384f436b99.Client.Models;

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_c41c24300fbf48f9881eb8384f436b99.Client.Models;

namespace sv_c41c24300fbf48f9881eb8384f436b99.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_c41c24300fbf48f9881eb8384f436b99.Client.Models;

namespace sv_c41c24300fbf48f9881eb8384f436b99.Client.Services;

public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

using sv_c41c24300fbf48f9881eb8384f436b99.Client.Models;
using sv_c41c24300fbf48f9881eb8384f436b99.Client.Services;

namespace sv_c41c24300fbf48f9881eb8384f436b99.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 21, 6, 15, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTimeOffset(2026, 5, 19, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 21, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 21, 11, 45, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
            ]
        },
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate a slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c41c24300fbf48f9881eb8384f436b99.Client.Models
@using sv_c41c24300fbf48f9881eb8384f436b99.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IAsyncDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <span class="update-time">@update.Timestamp.ToString("g")</span> —
                    <span class="update-description">@update.Description</span>
                    <span class="update-location">(@update.Location)</span>
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }
}

